INSERT INTO `question_discussion` VALUES (1,2,110,'using git filter-repo might help',NULL,NULL,'2023-01-11 04:18:21','2023-01-11 04:18:21'),(2,1,41,'khó quá',NULL,NULL,'2023-01-12 08:17:31','2023-01-12 08:17:31'),(3,3,41,'quá dễ',NULL,NULL,'2023-01-12 09:12:06','2023-01-12 09:12:06'),(4,3,41,'good',NULL,NULL,'2023-01-12 09:14:58','2023-01-12 09:14:58'),(5,3,1,'test',NULL,NULL,'2023-01-12 10:03:51','2023-01-12 10:03:51'),(6,1,1,'test 2',NULL,NULL,'2023-01-13 01:59:20','2023-01-13 01:59:20'),(7,1,1,'An item or event of a system that could be verified by one or more test conditions, e.g., a function, transaction, feature, quality attribute, or structural element.',NULL,NULL,'2023-01-13 02:13:01','2023-01-13 02:13:01'),(8,1,1,'An item or event of a system that could be verified by one or more test conditions, e.g., a function, transaction, feature, quality attribute, or structural element.',NULL,NULL,'2023-01-13 03:04:07','2023-01-13 03:04:07'),(9,1,1,'Mr. Test has been testing software applications on mobile devices for a period of 5 years. He has a wealth of experience in testing mobile applications and achieves better results in a shorter time than others. Over several months Mr. Test did not modify the existing automated test cases and did not create any new test cases. This leads to fewer and fewer defects being found by executing the tests. What principle of testing did Mr. Test not observe?',NULL,NULL,'2023-01-13 03:21:07','2023-01-13 03:21:07'),(10,3,41,'test',NULL,NULL,'2023-01-13 07:06:49','2023-01-13 07:06:49'),(11,3,41,'An item or event of a system that could be verified by one or more test conditions, e.g., a function, transaction, feature, quality attribute, or structural element.',NULL,NULL,'2023-01-13 07:07:00','2023-01-13 07:07:00'),(12,2,212,'hehe\n',NULL,NULL,'2023-01-13 08:43:05','2023-01-13 08:43:05'),(13,1,137,'lll',NULL,NULL,'2023-02-17 02:56:39','2023-02-17 02:56:39');
